def split_thinking_content(text: str) -> tuple[str, str]:
    if not text:
        return "", ""
    src = str(text)
    thinking_parts: list[str] = []

    def _collect(group_text: str):
        s = str(group_text or "").strip()
        if s:
            thinking_parts.append(s)

    def _repl_block(m: re.Match) -> str:
        _collect(m.group(1))
        return ""

    # Scan <think> blocks leniently: if closing tag is missing, treat tail as thinking.
    body_parts: list[str] = []
    pos = 0
    while pos < len(src):
        open_m = re.search(r"(?is)<think\b[^>]*>", src[pos:])
        if not open_m:
            body_parts.append(src[pos:])
            break
        open_start = pos + open_m.start()
        open_end = pos + open_m.end()
        body_parts.append(src[pos:open_start])
        close_m = re.search(r"(?is)</think\s*>", src[open_end:])
        if close_m:
            close_start = open_end + close_m.start()
            close_end = open_end + close_m.end()
            _collect(src[open_end:close_start])
            pos = close_end
            continue
        _collect(src[open_end:])
        pos = len(src)
        break
    body = "".join(body_parts)
    body = re.sub(r"(?is)```(?:thinking|reasoning)\s*([\s\S]*?)```", _repl_block, body)
    body = re.sub(r"(?is)<\|start_of_thought\|>(.*?)<\|end_of_thought\|>", _repl_block, body)
    body = re.sub(r"\n{3,}", "\n\n", body).strip()
    thinking = "\n\n".join(part for part in thinking_parts if part).strip()
    return body, trim(thinking, 24_000) if thinking else ""

def strip_thinking_content(text: str) -> str:
    return split_thinking_content(text)[0]

def check_ollama_model_ready(base_url: str, model: str, timeout: int = 10) -> tuple[bool, str]:
    if not model:
        return False, "model required"
    url = f"{base_url.rstrip('/')}/api/show"
    payload = {
        "name": model,
    }
    req = Request(
        url,
        data=json_dumps(payload).encode("utf-8"),
        headers={"Content-Type": "application/json"},
        method="POST",
    )
    try:
        with urlopen(req, timeout=timeout) as resp:
            _ = resp.read()
        return True, ""
    except HTTPError as exc:
        text = exc.read().decode("utf-8", errors="replace")
        low = text.lower()
        if exc.code == 404 or "not found" in low:
            return False, f"not found: {model}"
        return False, f"HTTP {exc.code}: {text}"
    except Exception as exc:
        return False, str(exc)

