def extract_openai_compat_model_ids(payload: object) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    def _add(value: object):
        text = trim(str(value or "").strip(), 240)
        if not text:
            return
        low = text.lower()
        if low in {"list", "model", "models", "object", "data"}:
            return
        if text in seen:
            return
        seen.add(text)
        out.append(text)
    def _walk(node: object, depth: int = 0):
        if depth > 5 or node is None:
            return
        if isinstance(node, list):
            for item in node:
                _walk(item, depth + 1)
            return
        if isinstance(node, dict):
            for key in ("id", "model", "name"):
                value = node.get(key)
                if isinstance(value, (str, int, float)):
                    _add(value)
            for key in ("data", "models", "items", "result", "results", "value"):
                if key in node:
                    _walk(node.get(key), depth + 1)
            return
        if depth <= 1 and isinstance(node, (str, int, float)):
            _add(node)
    _walk(payload, 0)
    return out

def _is_http_url(text: str) -> bool:
    try:
        p = urlparse(str(text or "").strip())
        return p.scheme.lower() in {"http", "https"}
    except Exception:
        return False

def _resolve_local_path(raw: str, base_dir: Path) -> Path:
    src = str(raw or "").strip()
    if not src:
        raise ValueError("empty path")
    p = urlparse(src)
    if p.scheme.lower() == "file":
        file_part = unquote(p.path or "")
        if p.netloc:
            file_part = f"/{p.netloc}{file_part}"
        path = Path(file_part)
    else:
        path = Path(src).expanduser()
    if not path.is_absolute():
        path = (base_dir / path).resolve()
    else:
        path = path.resolve()
    return path

